def compute_signals(bars: list, params: dict) -> list:
    '''
    bars: list of dicts with ONLY 6 keys: datetime, open, high, low, close, volume
    params: merged factor params dict, e.g. {"fast_period": 20, "slow_period": 60}
    Returns: list of int (same length as bars) — 1=long, -1=short, 0=flat

    CRITICAL REQUIREMENTS:
    - bars[i] ONLY has: datetime, open, high, low, close, volume
    - DO NOT access bars[i]["MACD"], bars[i]["RSI"], bars[i]["EMA"] — THESE DO NOT EXIST!
    - MUST use ta_* functions for ALL indicators (ta_macd, ta_rsi, ta_ema, ta_sma, etc.)
    - Implement ALL factors: ['BollingerBands', 'VolumeRatio', 'ATR']
    - params dict keys match the factor param names exactly
    - Apply market_filter conditions: ['atr > 0.003 * close', 'bb_position > 0.4 and bb_position < 0.6']
    - Long entry when: bb_bandwidth < 0.06 and volume_ratio > 1.3 and atr > 0.003 * close and close > bollinger_upper
    - Short entry when: bb_bandwidth < 0.06 and volume_ratio > 1.3 and atr > 0.003 * close and close < bollinger_lower
    - confirm_bars=1: signal must be consistent for N bars before confirming
    - Use ONLY the pre-built ta_* functions + Python stdlib + math module (NO pandas, NO numpy, NO ta-lib)
    - Return exactly len(bars) integers

    OPTIMIZATION GUIDANCE (if feedback provided):
    - If trade count is too low: consider relaxing filter thresholds (ATR/ADX/volume_ratio)
    - If Sharpe is too low: tighten entry conditions to improve quality
    - Balance between trade frequency and trade quality
    - DO NOT remove core factors or violate hard constraints
    '''
    n = len(bars)
    if n == 0:
        return []

    def _date_key(dt):
        s = str(dt)
        if "T" in s:
            return s.split("T", 1)[0]
        if " " in s:
            return s.split(" ", 1)[0]
        return s[:10]

    def _get_param(name, default):
        if name in params:
            return params.get(name, default)
        if "BollingerBands" in params and isinstance(params["BollingerBands"], dict) and name in params["BollingerBands"]:
            return params["BollingerBands"].get(name, default)
        if "VolumeRatio" in params and isinstance(params["VolumeRatio"], dict) and name in params["VolumeRatio"]:
            return params["VolumeRatio"].get(name, default)
        if "ATR" in params and isinstance(params["ATR"], dict) and name in params["ATR"]:
            return params["ATR"].get(name, default)
        alias_map = {
            "period": ["bb_period", "volume_ratio_period", "atr_period"],
            "std_dev": ["bb_std_dev", "bollinger_std_dev"],
        }
        for alias in alias_map.get(name, []):
            if alias in params:
                return params.get(alias, default)
        return default

    closes = [float(b.get("close", 0.0)) for b in bars]
    highs = [float(b.get("high", 0.0)) for b in bars]
    lows = [float(b.get("low", 0.0)) for b in bars]
    volumes = [float(b.get("volume", 0.0)) for b in bars]
    dates = [_date_key(b.get("datetime", "")) for b in bars]

    bb_period = int(_get_param("period", 20))
    bb_std_dev = float(_get_param("std_dev", 2.0))

    vr_period = 20
    if "VolumeRatio" in params and isinstance(params["VolumeRatio"], dict):
        vr_period = int(params["VolumeRatio"].get("period", 20))
    elif "volume_ratio_period" in params:
        vr_period = int(params.get("volume_ratio_period", 20))

    atr_period = 14
    if "ATR" in params and isinstance(params["ATR"], dict):
        atr_period = int(params["ATR"].get("period", 14))
    elif "atr_period" in params:
        atr_period = int(params.get("atr_period", 14))

    upper, middle, lower = ta_bollinger(closes, period=bb_period, std_dev=bb_std_dev)
    volume_ratio = ta_volume_ratio(volumes, period=vr_period)
    atr = ta_atr(highs, lows, closes, period=atr_period)

    bb_position = [0.5] * n
    bb_bandwidth = [0.0] * n
    for i in range(n):
        u = upper[i]
        m = middle[i]
        l = lower[i]
        c = closes[i]
        band_range = u - l
        if band_range > 0:
            bb_position[i] = (c - l) / band_range
        else:
            bb_position[i] = 0.5
        if m and m != 0:
            bb_bandwidth[i] = band_range / m
        elif c != 0:
            bb_bandwidth[i] = band_range / c
        else:
            bb_bandwidth[i] = 0.0

    confirm_bars = int(params.get("confirm_bars", 1))
    if confirm_bars < 1:
