    position = 0

    for i in range(n):
        is_last_bar_of_day = (i == n - 1) or (dates[i] != dates[i + 1])

        if i > 0 and dates[i] != dates[i - 1]:
            position = 0
            long_count = 0
            short_count = 0

        if raw_long[i]:
            long_count += 1
            short_count = 0
        elif raw_short[i]:
            short_count += 1
            long_count = 0
        else:
            long_count = 0
            short_count = 0

        if position == 0:
            if long_count >= confirm_bars:
                position = 1
            elif short_count >= confirm_bars:
                position = -1
        elif position == 1:
            exit_long = (
                closes[i] < middle[i]
                or closes[i] < closes[i - 1] - 0.5 * atr[i] if i > 0 else False
                or raw_short[i]
            )
            if exit_long:
                position = 0
                if short_count >= confirm_bars:
                    position = -1
        elif position == -1:
            exit_short = (
                closes[i] > middle[i]
                or closes[i] > closes[i - 1] + 0.5 * atr[i] if i > 0 else False
                or raw_long[i]
            )
            if exit_short:
                position = 0
                if long_count >= confirm_bars:
                    position = 1

        if is_last_bar_of_day:
            signals[i] = 0
            position = 0
            long_count = 0
            short_count = 0
        else:
            signals[i] = position

    return signals
